import React, { useState, useEffect } from "react";
import "./Popup.css"; // Add styles for the popup

// Import images from the src folder
import image1 from "../assets/Popup1.jpg";
import image2 from "../assets/Popup2.jpg";
import image3 from "../assets/Popup3.jpg";

const Popup = () => {
  const [showPopup, setShowPopup] = useState(true);
  const [currentSlide, setCurrentSlide] = useState(0);

  const closePopup = () => {
    setShowPopup(false); // Close the popup when clicking the close button
  };

  const images = [image1, image2, image3]; // Use the imported images

  const nextSlide = () => {
    setCurrentSlide((prevSlide) => (prevSlide + 1) % images.length); // Go to the next slide
  };

  const prevSlide = () => {
    setCurrentSlide((prevSlide) => (prevSlide - 1 + images.length) % images.length); // Go to the previous slide
  };

  // Optional: Add a delay to auto-close popup after some time
  useEffect(() => {
    const timer = setTimeout(() => {
      setShowPopup(false); // Close the popup after 5 seconds (optional)
    }, 5000); // Close after 5 seconds
    return () => clearTimeout(timer); // Cleanup on component unmount
  }, []);

  return (
    <div>
      {showPopup && (
        <div className="popup-overlay">
          <div className="popup-content">
            <button className="close-button" onClick={closePopup}>
              &times;
            </button>
            <div className="popup-body">
              <h2>Book Now, Pay Later With 0% Interest</h2>
              <p>Book Now & Pay in 3 Easy Installments!</p>
              <div className="slider-container">
                <button className="slider-button" onClick={prevSlide}>&lt;</button>
                <img
                  src={images[currentSlide]} // Display the current slide image
                  alt={`Slide ${currentSlide + 1}`}
                  className="popup-image"
                />
                <button className="slider-button" onClick={nextSlide}>&gt;</button>
              </div>
              <p className="popup-terms">T&C Apply. Contact us for more info!</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Popup;
